import{_ as e,o as d,c as a,ae as r}from"./chunks/framework.CDhj6wcg.js";const p=JSON.parse('{"title":"SKILLS.md — Spravel Starter Kit Capabilities","description":"","frontmatter":{},"headers":[],"relativePath":"SKILLS.md","filePath":"SKILLS.md"}'),o={name:"SKILLS.md"};function i(n,t,s,l,c,h){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="skills-md-—-spravel-starter-kit-capabilities" tabindex="-1">SKILLS.md — Spravel Starter Kit Capabilities <a class="header-anchor" href="#skills-md-—-spravel-starter-kit-capabilities" aria-label="Permalink to &quot;SKILLS.md — Spravel Starter Kit Capabilities&quot;">​</a></h1><blockquote><p>Dokumen ini menjelaskan apa saja yang sudah bisa dilakukan oleh starter kit ini sebagai referensi saat mengembangkan fitur baru atau onboarding developer baru.</p></blockquote><hr><h2 id="_1-authentication" tabindex="-1">1. Authentication <a class="header-anchor" href="#_1-authentication" aria-label="Permalink to &quot;1. Authentication&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kemampuan</th><th>Status</th><th>Catatan</th></tr></thead><tbody><tr><td>Login dengan username + password</td><td>✅ Done</td><td>BCrypt password hashing</td></tr><tr><td>JWT Access Token</td><td>✅ Done</td><td>Embed <code>perms[]</code> slug di dalam token</td></tr><tr><td>JWT Refresh Token</td><td>✅ Done</td><td>Refresh otomatis di interceptor frontend</td></tr><tr><td>Token revoke (logout)</td><td>✅ Done</td><td>Token disimpan di DB, bisa di-revoke</td></tr><tr><td>Force logout semua sesi</td><td>✅ Done</td><td><code>POST /api/v1/auth/force-logout-all</code></td></tr><tr><td>Fetch user info (<code>/me</code>)</td><td>✅ Done</td><td>Return user + roles + permissions</td></tr></tbody></table><hr><h2 id="_2-role-permission-rbac-acl" tabindex="-1">2. Role &amp; Permission (RBAC + ACL) <a class="header-anchor" href="#_2-role-permission-rbac-acl" aria-label="Permalink to &quot;2. Role &amp; Permission (RBAC + ACL)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kemampuan</th><th>Status</th><th>Catatan</th></tr></thead><tbody><tr><td>Module management</td><td>✅ Done</td><td>Grouping permission (e.g. &quot;Posts Module&quot;)</td></tr><tr><td>Permission management</td><td>✅ Done</td><td>Slug-based (e.g. <code>post.index</code>, <code>post.store</code>)</td></tr><tr><td>Role management</td><td>✅ Done</td><td>Setiap role punya slug unik</td></tr><tr><td>Assign permission ke role</td><td>✅ Done</td><td>ACL matrix per role</td></tr><tr><td>Assign role ke user</td><td>✅ Done</td><td>User bisa punya banyak role (M2M)</td></tr><tr><td>Permission di-embed ke JWT</td><td>✅ Done</td><td>Tidak perlu query DB setiap request</td></tr><tr><td>Permission di-refresh saat token refresh</td><td>✅ Done</td><td>Saat access token expired, permissions di-reload dari DB</td></tr><tr><td>Backend check permission (<code>@PreAuthorize</code>)</td><td>✅ Done</td><td>Via Spring Security method security</td></tr><tr><td>Frontend route guard by permission</td><td>✅ Done</td><td>Via Vue Router <code>meta.permission</code></td></tr><tr><td>Frontend composable <code>can(slug)</code></td><td>⏳ Perlu dibuat</td><td>Helper cek permission di template</td></tr></tbody></table><hr><h2 id="_3-crud-modules" tabindex="-1">3. CRUD Modules <a class="header-anchor" href="#_3-crud-modules" aria-label="Permalink to &quot;3. CRUD Modules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Index</th><th>Show</th><th>Store</th><th>Update</th><th>Delete</th></tr></thead><tbody><tr><td>Post</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Category</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Role</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Permission</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Module</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>User</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><hr><h2 id="_4-api-layer" tabindex="-1">4. API Layer <a class="header-anchor" href="#_4-api-layer" aria-label="Permalink to &quot;4. API Layer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kemampuan</th><th>Status</th><th>Catatan</th></tr></thead><tbody><tr><td>Standardized API response wrapper</td><td>✅ Done</td><td><code>ResData&lt;T&gt;</code> dengan <code>status</code>, <code>message</code>, <code>data</code></td></tr><tr><td>Flat DTO design (hindari circular reference)</td><td>✅ Done</td><td><code>PermissionResponse.moduleSlug</code></td></tr><tr><td>Pagination support</td><td>✅ Done</td><td>Spring Data <code>Page&lt;T&gt;</code></td></tr><tr><td>Global exception handler</td><td>✅ Done</td><td><code>GlobalExceptionHandler</code> → <code>ResData&lt;ErrorData&gt;</code></td></tr><tr><td>Custom 401/403 handler</td><td>✅ Done</td><td><code>CustomAuthEntryPoint</code>, <code>CustomAccessDeniedHandler</code></td></tr><tr><td>HTTP request logger</td><td>✅ Done</td><td><code>HttpLogFilter</code> middleware</td></tr><tr><td>Input validation</td><td>✅ Done</td><td>Bean Validation (<code>@Valid</code>)</td></tr></tbody></table><hr><h2 id="_5-frontend" tabindex="-1">5. Frontend <a class="header-anchor" href="#_5-frontend" aria-label="Permalink to &quot;5. Frontend&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kemampuan</th><th>Status</th><th>Catatan</th></tr></thead><tbody><tr><td>Login page</td><td>✅ Done</td><td></td></tr><tr><td>Dashboard layout (sidebar + header)</td><td>✅ Done</td><td><code>AppLayout.vue</code></td></tr><tr><td>Auth state management (Pinia)</td><td>✅ Done</td><td>Token + user + permissions di localStorage</td></tr><tr><td>Axios interceptor (auto token inject + refresh)</td><td>✅ Done</td><td><code>api.js</code></td></tr><tr><td>Route guard (requiresAuth + permission)</td><td>✅ Done</td><td><code>router/index.js</code></td></tr><tr><td>UI Component library</td><td>✅ Done</td><td>Radix Vue + Tailwind CSS</td></tr><tr><td>Sidebar menu hidden jika tidak punya permission</td><td>⏳ Perlu dibuat</td><td>Cek <code>can()</code> di sidebar item</td></tr><tr><td>Composable <code>usePermission()</code> / <code>can()</code></td><td>⏳ Perlu dibuat</td><td></td></tr></tbody></table><hr><h2 id="_6-developer-experience" tabindex="-1">6. Developer Experience <a class="header-anchor" href="#_6-developer-experience" aria-label="Permalink to &quot;6. Developer Experience&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kemampuan</th><th>Status</th><th>Catatan</th></tr></thead><tbody><tr><td>Database seeder</td><td>✅ Done</td><td><code>MainSeeder</code> + <code>UserSeeder</code>, auto-run via config</td></tr><tr><td>Hot reload frontend (Vite)</td><td>✅ Done</td><td><code>pnpm run dev</code> proxy ke port 8090</td></tr><tr><td>Single JAR deployment</td><td>✅ Done</td><td>Maven <code>package</code> embed frontend</td></tr><tr><td>Environment config</td><td>✅ Done</td><td><code>application.properties</code></td></tr></tbody></table><hr><h2 id="checklist-yang-masih-perlu-dibuat" tabindex="-1">Checklist: Yang Masih Perlu Dibuat <a class="header-anchor" href="#checklist-yang-masih-perlu-dibuat" aria-label="Permalink to &quot;Checklist: Yang Masih Perlu Dibuat&quot;">​</a></h2><ul><li>[ ] User CRUD (dengan assign role)</li><li>[ ] Frontend composable <code>can(slug)</code> untuk cek permission di komponen</li><li>[ ] Sidebar item hidden/disabled berdasarkan permission</li><li>[ ] Notifikasi toast global</li><li>[ ] Konfirmasi dialog reusable</li><li>[ ] Profile page (edit profil, ganti password)</li><li>[ ] Audit log UI (tampilkan <code>LogHttp</code>)</li><li>[ ] Unit test backend (service layer)</li><li>[ ] API documentation (Swagger/OpenAPI)</li></ul>',23)])])}const m=e(o,[["render",i]]);export{p as __pageData,m as default};
